def normalize_cmd(cmd: tuple[str, ...]) -> tuple[str, ...]:

    if not cmd:
        return cmd

    # Normalize the command by handling shebang and deep paths
    normalized_cmd = []
    for part in cmd:
        if part.startswith('#!'):
            # Handle shebang
            normalized_cmd.append(part)
        else:
            # Normalize the path
            normalized_cmd.append(part.replace('\\', '/'))

    return tuple(normalized_cmd)

