def size_to_bytes(size: str) -> int:

    size = size.strip().upper()
    multipliers = {
        'K': 1000,
        'M': 1000**2,
        'G': 1000**3,
        'T': 1000**4,
        'P': 1000**5,
        'E': 1000**6,
    }

    if size.isdigit():
        return int(size)

    for suffix, multiplier in multipliers.items():
        if size.endswith(suffix):
            return int(float(size[:-1]) * multiplier)

    raise ValueError("Invalid size format")

