    if day is not None:
        day = int(day)
    if week is not None:
        week = int(week)
    if weekday is not None:
        weekday = int(weekday)

    if week is not None:
        # ISO week date
        if weekday is None:
            weekday = 1  # Default to Monday
        date = datetime.fromisocalendar(year, week, weekday)
    else:
        # Regular date
        if month is None:
            month = 1  # Default to January
